import{_ as e,o as a,c as r,a4 as o}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"月光效应","description":"","frontmatter":{"title":"月光效应","phenomenon":"adularescence"},"headers":[],"relativePath":"zh/optical-phenomena/adularescence.md","filePath":"zh/optical-phenomena/adularescence.md","lastUpdated":1784176423000}'),d={name:"zh/optical-phenomena/adularescence.md"};function n(l,t,i,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="月光效应" tabindex="-1">月光效应 <a class="header-anchor" href="#月光效应" aria-label="Permalink to &quot;月光效应&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>月光石（长石族）的标志性效应。在弧面切割下，宝石内部呈现一片 柔和、漂浮的蓝色至白色光晕，仿佛月光在水面游动。机制是正长石 与钠长石薄层交替（每层 ~100–300 nm），层间折射率差产生光的散射 与干涉。这是结构引起的光学现象，与色心、致色元素无关。</p><h2 id="机制" tabindex="-1">机制 <a class="header-anchor" href="#机制" aria-label="Permalink to &quot;机制&quot;">​</a></h2><p>层状散射 + 干涉：交替生长的 KAlSi₃O₈（正长石）与 NaAlSi₃O₈ （钠长石）薄层厚度恰好与可见光波长同数量级。当光波通过层间 时发生相干散射，蓝光（短波长）相位匹配产生建设性干涉 → 形成 蓝/银色漂浮光晕。橙色与红色因波长更长而干涉相消，因此月光 总是蓝白色调。</p><h2 id="示例宝石" tabindex="-1">示例宝石 <a class="header-anchor" href="#示例宝石" aria-label="Permalink to &quot;示例宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>层状结构</th><th>基质矿物</th></tr></thead><tbody><tr><td>Blue Moonstone / 蓝月光石</td><td>orthoclase + albite</td><td>feldspar</td></tr><tr><td>Rainbow Moonstone / 彩虹月光石</td><td>fine alternating (rainbow CT interference)</td><td>feldspar</td></tr><tr><td>White Moonstone / 白月光石</td><td>orthoclase + albite (coarser)</td><td>feldspar</td></tr><tr><td>Cat&#39;s-eye Moonstone / 猫眼月光石</td><td>orthoclase + albite + oriented needles</td><td>feldspar</td></tr></tbody></table><p><em>详见<a href="./intro.html">光学现象总览</a>。</em></p>',8)])])}const _=e(d,[["render",n]]);export{m as __pageData,_ as default};
